function solve(landStartTime: number[], landDuration: number[], waterStartTime: number[], waterDuration: number[]): number {
    // Helper function to calculate the end time of an attraction
    function getEndtime(start: number, duration: number): number {
        return start + duration;
    }

    // Calculate all possible end times for land and water attractions
    const landEndTimes: number[] = landStartTime.map((start, i) => getEndtime(start, landDuration[i]));
    const waterEndTimes: number[] = waterStartTime.map((start, j) => getEndtime(start, waterDuration[j]));

    // Calculate all possible combinations of land and water attractions
    let minTime = Infinity;
    for (let i = 0; i < landEndTimes.length; i++) {
        for (let j = 0; j < waterEndTimes.length; j++) {
            // Case 1: Land first, then water
            const landEnd = landEndTimes[i];
            const waterStart = Math.max(landEnd, waterStartTime[j]);
            const waterEnd = getEndtime(waterStart, waterDuration[j]);
            minTime = Math.min(minTime, waterEnd);

            // Case 2: Water first, then land
            const waterEnd = waterEndTimes[j];
            const landStart = Math.max(waterEnd, landStartTime[i]);
            const landEnd = getEndtime(landStart, landDuration[i]);
            minTime = Math.min(minTime, landEnd);
        }
    }

    return minTime;
}
